(function ($, window, Drupal, drupalSettings) {
  Drupal.behaviors.bdcMessage = {
    attach: function (context, settings) {
      // console.log(settings);
      $("body", context).once('bdcMessages').each(this.SetupbdcMessages);
    },

    SetupbdcMessages: function (idx, column) {
      // <p class=\'bdc-card-title-msg uk-margin-remove-bottom\' style=\'font-size:12px;\'>" + message.state +"</p>
      console.log(drupalSettings);
      // console.log(Drupal);
      if (drupalSettings.bdcMessage) {
        var allMessage = drupalSettings.bdcMessage;
        var uiKit = UIkit;
        // console.log(drupalSettings.bdcMessage);
        allMessage.forEach(function (message) {
          console.log(message);
          if (message.state == 'danger') {
            var icon = 'ban';
          } else if (message.state == 'warning') {
            var icon = 'warning';
          } else {
            var icon = 'check';
          }
          uiKit.notification(
            "<div class=\'uk-card-header uk-padding-remove\'><div class=\'uk-grid-small uk-flex-middle\' uk-grid><div class=\'uk-width-auto\'></span><a href=\'#\' class=\'uk-icon-button\' uk-icon=\'" + icon + "\'></a></div><div class=\'uk-width-expand\'><p class=\'bdc-text-meta-msg uk-margin-remove-top uk-link-text\' style=\'font-size:15px;\'>" + message.msg +" </p></div></div></div>",
            { pos: 'bottom-right', status: message.state, timeout: '7000' }
          );
        });
      }
    },
  };


})(jQuery, window, Drupal, drupalSettings);

